frontend_integration.css_styles:
.timer-container {
    position: fixed;
    top: 20px;
    right: 20px;
    background: white;
    padding: 15px;
    border-radius: 10px;
    box-shadow: 0 4px 6px rgba(0,0,0,0.1);
    z-index: 1000;
    min-width: 200px;
}

.timer-display {
    font-size: 24px;
    font-weight: bold;
    text-align: center;
    margin-bottom: 10px;
}

.progress-bar {
    width: 100%;
    height: 8px;
    background: #e0e0e0;
    border-radius: 4px;
    overflow: hidden;
}

.progress-fill {
    height: 100%;
    background: linear-gradient(90deg, #28A745, #FFC107, #DC3545);
    transition: width 1s linear;
}

.warning-message {
    background: #FFF3CD;
    border: 2px solid #FFC107;
    border-radius: 5px;
    padding: 10px;
    margin-top: 10px;
    animation: pulse 1s infinite;
}

.warning-icon {
    font-size: 20px;
    margin-right: 10px;
}

.warning-text {
    font-weight: bold;
    color: #856404;
}

@keyframes pulse {
    0% { transform: scale(1); }
    50% { transform: scale(1.05); }
    100% { transform: scale(1); }
}

.time-plenty { color: #28A745; }
.time-moderate { color: #FFC107; }
.time-low { color: #DC3545; }
.time-warning { color: #FF6B6B; animation: blink 0.5s infinite; }

@keyframes blink {
    0%, 50% { opacity: 1; }
    25%, 75% { opacity: 0.5; }
}

frontend_integration.javascript_logic:
class EnhancedTimer {
    constructor(totalSeconds, warningCallback) {
        this.totalSeconds = totalSeconds;
        this.remainingSeconds = totalSeconds;
        this.warningCallback = warningCallback;
        this.warningShown = false;
        this.intervalId = null;
    }

    start() {
        this.intervalId = setInterval(() => this.update(), 1000);
    }

    update() {
        this.remainingSeconds--;
        this.updateDisplay();

        if (this.remainingSeconds === 10 && !this.warningShown) {
            this.showWarning();
            this.warningShown = true;
            this.playWarningSound();
            this.vibrate();
        }

        if (this.remainingSeconds <= 0) {
            this.stop();
            this.warningCallback();
        }
    }

    updateDisplay() {
        const timerElement = document.getElementById('timer');
        const progressElement = document.getElementById('progress');

        if (timerElement) {
            timerElement.textContent = this.remainingSeconds;

            // Update color based on time remaining
            timerElement.className = 'time-remaining';
            const percentage = this.remainingSeconds / this.totalSeconds;

            if (percentage > 0.5) {
                timerElement.classList.add('time-plenty');
            } else if (percentage > 0.25) {
                timerElement.classList.add('time-moderate');
            } else if (percentage > 0.15) {
                timerElement.classList.add('time-low');
            } else {
                timerElement.classList.add('time-warning');
            }
        }

        if (progressElement) {
            const percentage = (this.totalSeconds - this.remainingSeconds) / this.totalSeconds * 100;
            progressElement.style.width = percentage + '%';
        }
    }

    showWarning() {
        const warningElement = document.getElementById('warning');
        if (warningElement) {
            warningElement.style.display = 'block';
            warningElement.style.animation = 'pulse 1s infinite';
        }
    }

    playWarningSound() {
        // Play warning sound if enabled
        if (this.soundEnabled) {
            const audio = new Audio('warning.mp3');
            audio.play().catch(e => console.log('Could not play sound'));
        }
    }

    vibrate() {
        // Vibrate if enabled
        if (this.vibrationEnabled && navigator.vibrate) {
            navigator.vibrate([200, 100, 200]);
        }
    }

    stop() {
        if (this.intervalId) {
            clearInterval(this.intervalId);
            this.intervalId = null;
        }
    }
}

// Usage in question component:
const timer = new EnhancedTimer(90, () => {
    // Time's up - submit answer or move to next question
    submitAnswer();
});
timer.start();
